import { useState } from "react";
import { useTranslation } from "react-i18next";
import { Badge } from "@/components/ui/badge";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Loader2, Clock, Check, BookOpen } from "lucide-react";
import { useIChingHistory } from "@/hooks/useIChingAgent";
import { format } from "date-fns";

const IChingHistoryTab = () => {
  const { t } = useTranslation();
  const [sceneFilter, setSceneFilter] = useState<string>("all");
  const { data: history, isLoading } = useIChingHistory(
    sceneFilter === "all" ? undefined : sceneFilter
  );

  const getSceneLabel = (scene: string) => {
    const map: Record<string, string> = {
      store_story: t("admin.ichingAgent.sceneStore"),
      post_neijing: t("admin.ichingAgent.scenePost"),
      dish_neijing: t("admin.ichingAgent.sceneDish"),
    };
    return map[scene] || scene;
  };

  if (isLoading) {
    return (
      <div className="flex justify-center py-12">
        <Loader2 className="w-6 h-6 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <div className="space-y-3">
      <div className="flex items-center gap-3">
        <Select value={sceneFilter} onValueChange={setSceneFilter}>
          <SelectTrigger className="w-40 h-8 text-xs">
            <SelectValue />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all" className="text-xs">{t("admin.ichingAgent.allScenes")}</SelectItem>
            <SelectItem value="store_story" className="text-xs">{t("admin.ichingAgent.sceneStore")}</SelectItem>
            <SelectItem value="post_neijing" className="text-xs">{t("admin.ichingAgent.scenePost")}</SelectItem>
            <SelectItem value="dish_neijing" className="text-xs">{t("admin.ichingAgent.sceneDish")}</SelectItem>
          </SelectContent>
        </Select>
        <span className="text-[10px] text-muted-foreground">
          {history?.length || 0} {t("admin.ichingAgent.records")}
        </span>
      </div>

      {(!history || history.length === 0) ? (
        <div className="flex flex-col items-center justify-center py-16 text-muted-foreground gap-2">
          <Clock className="w-8 h-8 opacity-30" />
          <p className="text-sm">{t("admin.ichingAgent.noHistory")}</p>
        </div>
      ) : (
        <div className="space-y-1.5">
          {history.map((item) => (
            <div key={item.id} className="rounded-md border bg-card p-3 space-y-1.5">
              <div className="flex items-center gap-1.5 flex-wrap">
                <Badge variant="outline" className="text-[10px] h-5">{getSceneLabel(item.scene_type)}</Badge>
                {item.hexagram_name && (
                  <Badge variant="secondary" className="text-[10px] h-5 gap-0.5">
                    <BookOpen className="w-2.5 h-2.5" />
                    {item.hexagram_name}
                  </Badge>
                )}
                {item.is_applied && (
                  <Badge className="text-[10px] h-5 gap-0.5 bg-green-600">
                    <Check className="w-2.5 h-2.5" />
                    {t("admin.ichingAgent.applied")}
                  </Badge>
                )}
                <span className="text-[10px] text-muted-foreground ml-auto flex items-center gap-1">
                  <Clock className="w-2.5 h-2.5" />
                  {format(new Date(item.created_at), "MM-dd HH:mm")}
                </span>
              </div>
              {item.reference_name && (
                <p className="text-[10px] text-muted-foreground">
                  {t("admin.ichingAgent.reference")}: {item.reference_name}
                </p>
              )}
              <p className="text-xs whitespace-pre-wrap line-clamp-3 leading-relaxed">{item.output_content}</p>
              <div className="flex items-center gap-2 text-[9px] text-muted-foreground">
                <span>v{item.version}</span>
                {item.model_used && <span>· {item.model_used}</span>}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default IChingHistoryTab;
