import { useState } from "react";
import { useTranslation } from "react-i18next";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
import { Badge } from "@/components/ui/badge";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Loader2, Search, Save, Pencil } from "lucide-react";
import { useIChingHexagrams, useUpdateHexagram, IChingHexagram } from "@/hooks/useIChingAgent";
import { toast } from "sonner";

const IChingHexagramsTab = () => {
  const { t } = useTranslation();
  const { data: hexagrams, isLoading } = useIChingHexagrams();
  const updateHex = useUpdateHexagram();
  const [search, setSearch] = useState("");
  const [editing, setEditing] = useState<IChingHexagram | null>(null);
  const [form, setForm] = useState<Partial<IChingHexagram>>({});

  const filtered = hexagrams?.filter(
    (h) =>
      h.name_zh.includes(search) ||
      h.name_en?.toLowerCase().includes(search.toLowerCase()) ||
      String(h.number).includes(search)
  );

  const openEdit = (h: IChingHexagram) => {
    setEditing(h);
    setForm({
      name_zh: h.name_zh,
      name_en: h.name_en,
      symbol: h.symbol,
      trigram_upper: h.trigram_upper,
      trigram_lower: h.trigram_lower,
      judgment_text: h.judgment_text,
      image_text: h.image_text,
      hexagram_text: h.hexagram_text,
      modern_interpretation: h.modern_interpretation,
      food_health_notes: h.food_health_notes,
    });
  };

  const handleSave = async () => {
    if (!editing) return;
    try {
      await updateHex.mutateAsync({ id: editing.id, ...form });
      toast.success(t("common.saved"));
      setEditing(null);
    } catch {
      toast.error(t("common.error"));
    }
  };

  if (isLoading) {
    return (
      <div className="flex justify-center py-12">
        <Loader2 className="w-6 h-6 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <div className="space-y-3">
      {/* Search + stats */}
      <div className="flex items-center gap-3">
        <div className="relative flex-1">
          <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-muted-foreground" />
          <Input
            placeholder={t("admin.ichingAgent.searchHexagram")}
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="pl-8 h-8 text-xs"
          />
        </div>
        <span className="text-[10px] text-muted-foreground shrink-0">
          {filtered?.length || 0} / 64
        </span>
      </div>

      {/* Grid */}
      <div className="grid grid-cols-4 sm:grid-cols-8 md:grid-cols-8 lg:grid-cols-8 gap-1.5">
        {filtered?.map((h) => (
          <button
            key={h.id}
            className="group relative flex flex-col items-center gap-0.5 p-2 rounded-md border bg-card hover:border-amber-500/50 hover:bg-amber-500/5 transition-all text-center"
            onClick={() => openEdit(h)}
          >
            <span className="text-lg leading-none">{h.symbol}</span>
            <span className="text-[11px] font-medium leading-tight">{h.name_zh}</span>
            <span className="text-[9px] text-muted-foreground">#{h.number}</span>
            {h.usage_count > 0 && (
              <span className="absolute top-1 right-1 w-1.5 h-1.5 rounded-full bg-amber-500" />
            )}
          </button>
        ))}
      </div>

      {/* Edit Dialog */}
      <Dialog open={!!editing} onOpenChange={(open) => !open && setEditing(null)}>
        <DialogContent className="max-w-2xl max-h-[85vh] flex flex-col p-0">
          <DialogHeader className="px-5 pt-5 pb-3 border-b">
            <DialogTitle className="flex items-center gap-2 text-base">
              <span className="text-xl">{editing?.symbol}</span>
              <span>#{editing?.number} {editing?.name_zh}</span>
              <Pencil className="w-3.5 h-3.5 text-muted-foreground" />
            </DialogTitle>
          </DialogHeader>

          <ScrollArea className="flex-1 px-5 py-4">
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <Label className="text-xs">{t("admin.ichingAgent.nameZh")}</Label>
                  <Input value={form.name_zh || ""} onChange={(e) => setForm({ ...form, name_zh: e.target.value })} className="h-8 text-sm" />
                </div>
                <div>
                  <Label className="text-xs">{t("admin.ichingAgent.nameEn")}</Label>
                  <Input value={form.name_en || ""} onChange={(e) => setForm({ ...form, name_en: e.target.value })} className="h-8 text-sm" />
                </div>
              </div>

              <div className="grid grid-cols-3 gap-3">
                <div>
                  <Label className="text-xs">{t("admin.ichingAgent.symbol")}</Label>
                  <Input value={form.symbol || ""} onChange={(e) => setForm({ ...form, symbol: e.target.value })} className="h-8 text-sm text-center" />
                </div>
                <div>
                  <Label className="text-xs">{t("admin.ichingAgent.upperTrigram")}</Label>
                  <Input value={form.trigram_upper || ""} onChange={(e) => setForm({ ...form, trigram_upper: e.target.value })} className="h-8 text-sm" />
                </div>
                <div>
                  <Label className="text-xs">{t("admin.ichingAgent.lowerTrigram")}</Label>
                  <Input value={form.trigram_lower || ""} onChange={(e) => setForm({ ...form, trigram_lower: e.target.value })} className="h-8 text-sm" />
                </div>
              </div>

              <div>
                <Label className="text-xs">{t("admin.ichingAgent.judgmentText")}</Label>
                <Textarea value={form.judgment_text || ""} onChange={(e) => setForm({ ...form, judgment_text: e.target.value })} rows={2} className="text-xs" />
              </div>

              <div>
                <Label className="text-xs">{t("admin.ichingAgent.imageText")}</Label>
                <Textarea value={form.image_text || ""} onChange={(e) => setForm({ ...form, image_text: e.target.value })} rows={2} className="text-xs" />
              </div>

              <div>
                <Label className="text-xs">{t("admin.ichingAgent.hexagramText")}</Label>
                <Textarea value={form.hexagram_text || ""} onChange={(e) => setForm({ ...form, hexagram_text: e.target.value })} rows={3} className="text-xs" placeholder={t("admin.ichingAgent.hexagramTextPlaceholder")} />
              </div>

              <div>
                <Label className="text-xs">{t("admin.ichingAgent.modernInterpretation")}</Label>
                <Textarea value={form.modern_interpretation || ""} onChange={(e) => setForm({ ...form, modern_interpretation: e.target.value })} rows={3} className="text-xs" placeholder={t("admin.ichingAgent.modernInterpretationPlaceholder")} />
              </div>

              <div>
                <Label className="text-xs">{t("admin.ichingAgent.foodHealthNotes")}</Label>
                <Textarea value={form.food_health_notes || ""} onChange={(e) => setForm({ ...form, food_health_notes: e.target.value })} rows={2} className="text-xs" placeholder={t("admin.ichingAgent.foodHealthNotesPlaceholder")} />
              </div>
            </div>
          </ScrollArea>

          <DialogFooter className="px-5 py-3 border-t">
            <Button variant="outline" size="sm" onClick={() => setEditing(null)}>
              {t("common.cancel")}
            </Button>
            <Button size="sm" onClick={handleSave} disabled={updateHex.isPending}>
              {updateHex.isPending ? <Loader2 className="w-3.5 h-3.5 animate-spin mr-1" /> : <Save className="w-3.5 h-3.5 mr-1" />}
              {t("common.save")}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
};

export default IChingHexagramsTab;
