import { useState } from "react";
import { useTranslation } from "react-i18next";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Switch } from "@/components/ui/switch";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle } from "@/components/ui/alert-dialog";
import { Badge } from "@/components/ui/badge";
import { Loader2, Plus, Pencil, Trash2, Globe, FileText, BookOpen } from "lucide-react";
import {
  useIChingKnowledgeSources,
  useAddKnowledgeSource,
  useUpdateKnowledgeSource,
  useDeleteKnowledgeSource,
  IChingKnowledgeSource,
} from "@/hooks/useIChingAgent";
import { toast } from "sonner";

const CATEGORY_ICONS: Record<string, typeof BookOpen> = {
  iching: BookOpen,
  neijing: FileText,
  food_health: FileText,
  other: FileText,
};

const IChingKnowledgeTab = () => {
  const { t } = useTranslation();
  const { data: sources, isLoading } = useIChingKnowledgeSources();
  const addSource = useAddKnowledgeSource();
  const updateSource = useUpdateKnowledgeSource();
  const deleteSource = useDeleteKnowledgeSource();

  const [dialogOpen, setDialogOpen] = useState(false);
  const [deleteId, setDeleteId] = useState<string | null>(null);
  const [editing, setEditing] = useState<IChingKnowledgeSource | null>(null);
  const [form, setForm] = useState({
    title: "",
    source_type: "text" as string,
    category: "iching" as string,
    content: "",
    url: "",
    is_active: true,
    sort_order: 0,
  });

  const openAdd = () => {
    setEditing(null);
    setForm({ title: "", source_type: "text", category: "iching", content: "", url: "", is_active: true, sort_order: 0 });
    setDialogOpen(true);
  };

  const openEdit = (src: IChingKnowledgeSource) => {
    setEditing(src);
    setForm({
      title: src.title,
      source_type: src.source_type,
      category: src.category,
      content: src.content,
      url: src.url || "",
      is_active: src.is_active,
      sort_order: src.sort_order,
    });
    setDialogOpen(true);
  };

  const handleSave = async () => {
    if (!form.title.trim()) return;
    try {
      if (editing) {
        await updateSource.mutateAsync({ id: editing.id, ...form, url: form.url || null });
      } else {
        await addSource.mutateAsync({ ...form, url: form.url || null } as any);
      }
      toast.success(t("common.saved"));
      setDialogOpen(false);
    } catch {
      toast.error(t("common.error"));
    }
  };

  const handleDelete = async () => {
    if (!deleteId) return;
    try {
      await deleteSource.mutateAsync(deleteId);
      toast.success(t("common.deleted"));
    } catch {
      toast.error(t("common.error"));
    }
    setDeleteId(null);
  };

  const getCategoryLabel = (cat: string) => {
    const map: Record<string, string> = {
      iching: t("admin.ichingAgent.catIChing"),
      neijing: t("admin.ichingAgent.catNeijing"),
      food_health: t("admin.ichingAgent.catFoodHealth"),
      other: t("admin.ichingAgent.catOther"),
    };
    return map[cat] || cat;
  };

  if (isLoading) {
    return (
      <div className="flex justify-center py-12">
        <Loader2 className="w-6 h-6 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <div className="space-y-4 mt-4">
      <div className="flex justify-end">
        <Button onClick={openAdd} size="sm">
          <Plus className="w-4 h-4 mr-1" />
          {t("admin.ichingAgent.addSource")}
        </Button>
      </div>

      {(!sources || sources.length === 0) ? (
        <p className="text-center text-muted-foreground py-8">{t("admin.ichingAgent.noSources")}</p>
      ) : (
        <div className="space-y-2">
          {sources.map((src) => {
            const Icon = CATEGORY_ICONS[src.category] || FileText;
            return (
              <Card key={src.id} className={!src.is_active ? "opacity-50" : ""}>
                <CardContent className="p-4 flex items-start gap-3">
                  <Icon className="w-5 h-5 text-amber-600 mt-0.5 shrink-0" />
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 flex-wrap">
                      <span className="font-medium text-sm">{src.title}</span>
                      <Badge variant="outline" className="text-[10px]">{getCategoryLabel(src.category)}</Badge>
                      {src.source_type === "url" && (
                        <Badge variant="secondary" className="text-[10px] gap-0.5">
                          <Globe className="w-3 h-3" /> URL
                        </Badge>
                      )}
                    </div>
                    <p className="text-xs text-muted-foreground mt-1 line-clamp-2">{src.content || src.url}</p>
                  </div>
                  <div className="flex gap-1 shrink-0">
                    <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => openEdit(src)}>
                      <Pencil className="w-3.5 h-3.5" />
                    </Button>
                    <Button variant="ghost" size="icon" className="h-8 w-8 text-destructive" onClick={() => setDeleteId(src.id)}>
                      <Trash2 className="w-3.5 h-3.5" />
                    </Button>
                  </div>
                </CardContent>
              </Card>
            );
          })}
        </div>
      )}

      {/* Add/Edit Dialog */}
      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent className="max-w-lg">
          <DialogHeader>
            <DialogTitle>
              {editing ? t("admin.ichingAgent.editSource") : t("admin.ichingAgent.addSource")}
            </DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            <div>
              <Label>{t("admin.ichingAgent.sourceTitle")}</Label>
              <Input value={form.title} onChange={(e) => setForm({ ...form, title: e.target.value })} />
            </div>
            <div className="grid grid-cols-2 gap-3">
              <div>
                <Label>{t("admin.ichingAgent.sourceType")}</Label>
                <Select value={form.source_type} onValueChange={(v) => setForm({ ...form, source_type: v })}>
                  <SelectTrigger><SelectValue /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="text">{t("admin.ichingAgent.typeText")}</SelectItem>
                    <SelectItem value="url">{t("admin.ichingAgent.typeUrl")}</SelectItem>
                    <SelectItem value="reference">{t("admin.ichingAgent.typeReference")}</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div>
                <Label>{t("admin.ichingAgent.sourceCategory")}</Label>
                <Select value={form.category} onValueChange={(v) => setForm({ ...form, category: v })}>
                  <SelectTrigger><SelectValue /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="iching">{t("admin.ichingAgent.catIChing")}</SelectItem>
                    <SelectItem value="neijing">{t("admin.ichingAgent.catNeijing")}</SelectItem>
                    <SelectItem value="food_health">{t("admin.ichingAgent.catFoodHealth")}</SelectItem>
                    <SelectItem value="other">{t("admin.ichingAgent.catOther")}</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </div>
            {form.source_type === "url" && (
              <div>
                <Label>URL</Label>
                <Input value={form.url} onChange={(e) => setForm({ ...form, url: e.target.value })} placeholder="https://..." />
              </div>
            )}
            <div>
              <Label>{t("admin.ichingAgent.sourceContent")}</Label>
              <Textarea value={form.content} onChange={(e) => setForm({ ...form, content: e.target.value })} rows={6} />
            </div>
            <div className="flex items-center gap-2">
              <Switch checked={form.is_active} onCheckedChange={(v) => setForm({ ...form, is_active: v })} />
              <Label>{t("admin.ichingAgent.sourceActive")}</Label>
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setDialogOpen(false)}>{t("common.cancel")}</Button>
            <Button onClick={handleSave} disabled={addSource.isPending || updateSource.isPending}>
              {(addSource.isPending || updateSource.isPending) && <Loader2 className="w-4 h-4 animate-spin mr-1" />}
              {t("common.save")}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Delete Confirm */}
      <AlertDialog open={!!deleteId} onOpenChange={() => setDeleteId(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>{t("common.confirmDelete")}</AlertDialogTitle>
            <AlertDialogDescription>{t("admin.ichingAgent.deleteSourceConfirm")}</AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>{t("common.cancel")}</AlertDialogCancel>
            <AlertDialogAction onClick={handleDelete}>{t("common.delete")}</AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
};

export default IChingKnowledgeTab;
