import { useState } from "react";
import { useTranslation } from "react-i18next";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Collapsible, CollapsibleContent, CollapsibleTrigger } from "@/components/ui/collapsible";
import { Loader2, Save, Sparkles, AlertTriangle, LayoutTemplate, Cpu, Dice5, ChevronDown, Settings } from "lucide-react";
import { useIChingAgentConfigs, useUpdateIChingAgentConfig } from "@/hooks/useIChingAgent";
import { toast } from "sonner";

const CONFIG_META: Record<string, { icon: typeof Settings; group: string }> = {
  system_prompt: { icon: Sparkles, group: "core" },
  generation_rules: { icon: Settings, group: "core" },
  cautions: { icon: AlertTriangle, group: "core" },
  divination_method: { icon: Dice5, group: "divination" },
  hexagram_selection_rules: { icon: Dice5, group: "divination" },
  yao_interpretation_rules: { icon: Dice5, group: "divination" },
  scene_store_story: { icon: LayoutTemplate, group: "scenes" },
  scene_post_neijing: { icon: LayoutTemplate, group: "scenes" },
  scene_dish_neijing: { icon: LayoutTemplate, group: "scenes" },
  model_name: { icon: Cpu, group: "params" },
  temperature: { icon: Cpu, group: "params" },
  max_tokens: { icon: Cpu, group: "params" },
};

const GROUP_ICONS: Record<string, typeof Settings> = {
  core: Sparkles,
  divination: Dice5,
  scenes: LayoutTemplate,
  params: Cpu,
};

const IChingAgentConfigTab = () => {
  const { t } = useTranslation();
  const { data: configs, isLoading } = useIChingAgentConfigs();
  const updateConfig = useUpdateIChingAgentConfig();
  const [editedValues, setEditedValues] = useState<Record<string, string>>({});
  const [savingKey, setSavingKey] = useState<string | null>(null);
  const [openGroups, setOpenGroups] = useState<Record<string, boolean>>({
    core: true,
    divination: false,
    scenes: false,
    params: true,
  });

  const getValue = (key: string) => {
    if (editedValues[key] !== undefined) return editedValues[key];
    return configs?.find((c) => c.config_key === key)?.config_value || "";
  };

  const handleSave = async (configItem: { id: string; config_key: string }) => {
    const newValue = editedValues[configItem.config_key];
    if (newValue === undefined) return;
    setSavingKey(configItem.config_key);
    try {
      await updateConfig.mutateAsync({ id: configItem.id, config_value: newValue });
      setEditedValues((prev) => {
        const n = { ...prev };
        delete n[configItem.config_key];
        return n;
      });
      toast.success(t("common.saved"));
    } catch {
      toast.error(t("common.error"));
    } finally {
      setSavingKey(null);
    }
  };

  const dirtyCount = Object.keys(editedValues).length;

  if (isLoading) {
    return (
      <div className="flex justify-center py-12">
        <Loader2 className="w-6 h-6 animate-spin text-primary" />
      </div>
    );
  }

  const renderGroup = (groupKey: string, title: string) => {
    const items = configs?.filter((c) => CONFIG_META[c.config_key]?.group === groupKey) || [];
    if (!items.length) return null;
    const GroupIcon = GROUP_ICONS[groupKey] || Settings;
    const groupDirtyCount = items.filter((item) => editedValues[item.config_key] !== undefined).length;

    return (
      <Collapsible
        key={groupKey}
        open={openGroups[groupKey]}
        onOpenChange={(open) => setOpenGroups((prev) => ({ ...prev, [groupKey]: open }))}
      >
        <CollapsibleTrigger asChild>
          <button className="w-full flex items-center gap-2 px-3 py-2.5 rounded-lg border bg-card hover:bg-accent/50 transition-colors group text-left">
            <GroupIcon className="w-4 h-4 text-amber-600 shrink-0" />
            <span className="text-sm font-medium flex-1">{title}</span>
            {groupDirtyCount > 0 && (
              <span className="text-[10px] bg-amber-500/15 text-amber-600 px-1.5 py-0.5 rounded-full font-medium">
                {groupDirtyCount} {t("admin.ichingAgent.unsaved")}
              </span>
            )}
            <span className="text-[10px] text-muted-foreground">{items.length}</span>
            <ChevronDown className="w-4 h-4 text-muted-foreground transition-transform duration-200 group-data-[state=open]:rotate-180" />
          </button>
        </CollapsibleTrigger>
        <CollapsibleContent>
          <div className="mt-2 space-y-3 pl-2">
            {items.map((item) => {
              const isParam = groupKey === "params";
              const isDirty = editedValues[item.config_key] !== undefined;
              const ItemIcon = CONFIG_META[item.config_key]?.icon || Settings;
              return (
                <div key={item.id} className={`rounded-lg border p-4 space-y-3 transition-colors ${isDirty ? "bg-amber-500/5 border-amber-500/20" : "bg-card/60"}`}>
                  <div className="flex items-center justify-between gap-2">
                    <div className="flex items-center gap-2">
                      <ItemIcon className="w-3.5 h-3.5 text-muted-foreground/60 shrink-0" />
                      <Label className="text-[13px] font-medium text-foreground/80">
                        {item.description || item.config_key}
                      </Label>
                    </div>
                    {isDirty && (
                      <Button
                        size="sm"
                        variant="outline"
                        className="h-7 text-xs gap-1.5 border-amber-500/30 text-amber-600 hover:bg-amber-500/10 rounded-md"
                        onClick={() => handleSave(item)}
                        disabled={savingKey === item.config_key}
                      >
                        {savingKey === item.config_key ? (
                          <Loader2 className="w-3 h-3 animate-spin" />
                        ) : (
                          <Save className="w-3 h-3" />
                        )}
                        {t("common.save")}
                      </Button>
                    )}
                  </div>
                  {isParam ? (
                    <Input
                      value={getValue(item.config_key)}
                      onChange={(e) =>
                        setEditedValues((prev) => ({ ...prev, [item.config_key]: e.target.value }))
                      }
                      className="font-mono text-[13px] h-9 rounded-lg bg-background/80 border-border/60 focus:border-primary/40 transition-colors"
                    />
                  ) : (
                    <Textarea
                      value={getValue(item.config_key)}
                      onChange={(e) =>
                        setEditedValues((prev) => ({ ...prev, [item.config_key]: e.target.value }))
                      }
                      rows={item.config_key === "system_prompt" ? 8 : 4}
                      className="text-[13px] leading-[1.75] resize-y min-h-[80px] rounded-lg bg-background/80 border-border/60 focus:border-primary/40 transition-colors placeholder:text-muted-foreground/40"
                    />
                  )}
                </div>
              );
            })}
          </div>
        </CollapsibleContent>
      </Collapsible>
    );
  };

  return (
    <div className="space-y-2">
      {dirtyCount > 0 && (
        <div className="flex items-center gap-2 px-3 py-2 rounded-md bg-amber-500/10 border border-amber-500/20 text-xs text-amber-700">
          <AlertTriangle className="w-3.5 h-3.5 shrink-0" />
          {t("admin.ichingAgent.unsavedChanges", { count: dirtyCount })}
        </div>
      )}
      {renderGroup("core", t("admin.ichingAgent.coreConfig"))}
      {renderGroup("divination", t("admin.ichingAgent.divinationRules"))}
      {renderGroup("scenes", t("admin.ichingAgent.sceneTemplates"))}
      {renderGroup("params", t("admin.ichingAgent.modelParams"))}
    </div>
  );
};

export default IChingAgentConfigTab;
