import { useState } from "react";
import { useTranslation } from "react-i18next";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { BookOpen, Settings, Database, History, MessageSquare, Sparkles } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import IChingAgentConfigTab from "./components/iching/IChingAgentConfigTab";
import IChingHexagramsTab from "./components/iching/IChingHexagramsTab";
import IChingKnowledgeTab from "./components/iching/IChingKnowledgeTab";
import IChingHistoryTab from "./components/iching/IChingHistoryTab";
import IChingTestChatTab from "./components/iching/IChingTestChatTab";

const AdminIChingAgent = () => {
  const { t } = useTranslation();
  const [activeTab, setActiveTab] = useState("config");

  return (
    <div className="space-y-4">
      {/* Compact header */}
      <div className="flex items-center gap-3">
        <div className="w-10 h-10 rounded-lg bg-gradient-to-br from-amber-500/20 to-amber-600/10 border border-amber-500/20 flex items-center justify-center shrink-0">
          <Sparkles className="w-5 h-5 text-amber-600" />
        </div>
        <div className="min-w-0">
          <h1 className="text-xl font-bold tracking-tight">{t("admin.ichingAgent.title")}</h1>
          <p className="text-xs text-muted-foreground truncate">{t("admin.ichingAgent.subtitle")}</p>
        </div>
        <Badge variant="outline" className="ml-auto text-[10px] shrink-0 border-amber-500/30 text-amber-600">
          v1.0
        </Badge>
      </div>

      <Tabs value={activeTab} onValueChange={setActiveTab} className="space-y-3">
        <TabsList className="h-9 p-0.5 w-full grid grid-cols-5 bg-muted/60">
          <TabsTrigger value="config" className="text-xs gap-1 h-8 data-[state=active]:shadow-sm">
            <Settings className="w-3.5 h-3.5" />
            <span className="hidden sm:inline">{t("admin.ichingAgent.configTab")}</span>
          </TabsTrigger>
          <TabsTrigger value="hexagrams" className="text-xs gap-1 h-8 data-[state=active]:shadow-sm">
            <BookOpen className="w-3.5 h-3.5" />
            <span className="hidden sm:inline">{t("admin.ichingAgent.hexagramsTab")}</span>
          </TabsTrigger>
          <TabsTrigger value="knowledge" className="text-xs gap-1 h-8 data-[state=active]:shadow-sm">
            <Database className="w-3.5 h-3.5" />
            <span className="hidden sm:inline">{t("admin.ichingAgent.knowledgeTab")}</span>
          </TabsTrigger>
          <TabsTrigger value="history" className="text-xs gap-1 h-8 data-[state=active]:shadow-sm">
            <History className="w-3.5 h-3.5" />
            <span className="hidden sm:inline">{t("admin.ichingAgent.historyTab")}</span>
          </TabsTrigger>
          <TabsTrigger value="test" className="text-xs gap-1 h-8 data-[state=active]:shadow-sm">
            <MessageSquare className="w-3.5 h-3.5" />
            <span className="hidden sm:inline">{t("admin.ichingAgent.testTab")}</span>
          </TabsTrigger>
        </TabsList>

        <TabsContent value="config" className="mt-0">
          <IChingAgentConfigTab />
        </TabsContent>
        <TabsContent value="hexagrams" className="mt-0">
          <IChingHexagramsTab />
        </TabsContent>
        <TabsContent value="knowledge" className="mt-0">
          <IChingKnowledgeTab />
        </TabsContent>
        <TabsContent value="history" className="mt-0">
          <IChingHistoryTab />
        </TabsContent>
        <TabsContent value="test" className="mt-0">
          <IChingTestChatTab />
        </TabsContent>
      </Tabs>
    </div>
  );
};

export default AdminIChingAgent;
