import { useState, useRef, useEffect, useCallback } from "react";
import { useTranslation } from "react-i18next";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Loader2, Send, Trash2, Sparkles, User, LayoutTemplate, Plus, MessageSquare, Clock } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import ReactMarkdown from "react-markdown";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { toast } from "sonner";

type Message = { role: "user" | "assistant"; content: string };

interface Conversation {
  id: string;
  title: string;
  messages: Message[];
  scene_type: string | null;
  created_at: string;
  updated_at: string;
}

const SCENE_OPTIONS = [
  { value: "none", labelKey: "admin.ichingAgent.noScene" },
  { value: "store_story", labelKey: "admin.ichingAgent.sceneStore" },
  { value: "post_neijing", labelKey: "admin.ichingAgent.scenePost" },
  { value: "dish_neijing", labelKey: "admin.ichingAgent.sceneDish" },
];

const IChingTestChatTab = () => {
  const { t } = useTranslation();
  const queryClient = useQueryClient();
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [sceneType, setSceneType] = useState("none");
  const [activeConversationId, setActiveConversationId] = useState<string | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  const saveTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Load conversation list
  const { data: conversations = [] } = useQuery({
    queryKey: ["iching-test-conversations"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("iching_test_conversations")
        .select("id, title, scene_type, created_at, updated_at")
        .order("updated_at", { ascending: false })
        .limit(20);
      if (error) throw error;
      return data as Pick<Conversation, "id" | "title" | "scene_type" | "created_at" | "updated_at">[];
    },
  });

  useEffect(() => {
    scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: "smooth" });
  }, [messages]);

  // Auto-save conversation after messages change (debounced)
  const saveConversation = useCallback(async (msgs: Message[], convId: string | null, scene: string) => {
    if (msgs.length === 0) return;
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;

    const title = msgs.find(m => m.role === "user")?.content.slice(0, 40) || t("admin.ichingAgent.newConversation");
    const sceneVal = scene === "none" ? null : scene;

    if (convId) {
      await supabase
        .from("iching_test_conversations")
        .update({ messages: msgs as any, title, scene_type: sceneVal } as any)
        .eq("id", convId);
    } else {
      const { data, error } = await supabase
        .from("iching_test_conversations")
        .insert({ user_id: user.id, messages: msgs as any, title, scene_type: sceneVal } as any)
        .select("id")
        .single();
      if (!error && data) {
        setActiveConversationId(data.id);
      }
    }
    queryClient.invalidateQueries({ queryKey: ["iching-test-conversations"] });
  }, [queryClient, t]);

  const debouncedSave = useCallback((msgs: Message[], convId: string | null, scene: string) => {
    if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
    saveTimerRef.current = setTimeout(() => saveConversation(msgs, convId, scene), 1500);
  }, [saveConversation]);

  // Load a conversation
  const loadConversation = async (id: string) => {
    const { data, error } = await supabase
      .from("iching_test_conversations")
      .select("*")
      .eq("id", id)
      .single();
    if (error || !data) return;
    setMessages((data.messages as any) || []);
    setSceneType(data.scene_type || "none");
    setActiveConversationId(id);
  };

  // New conversation
  const startNew = () => {
    setMessages([]);
    setInput("");
    setActiveConversationId(null);
    setSceneType("none");
  };

  // Delete conversation
  const deleteConversation = async (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    await supabase.from("iching_test_conversations").delete().eq("id", id);
    if (activeConversationId === id) startNew();
    queryClient.invalidateQueries({ queryKey: ["iching-test-conversations"] });
    toast.success(t("admin.ichingAgent.conversationDeleted"));
  };

  const handleSend = async () => {
    const text = input.trim();
    if (!text || isLoading) return;

    const userMsg: Message = { role: "user", content: text };
    const newMessages = [...messages, userMsg];
    setMessages(newMessages);
    setInput("");
    setIsLoading(true);

    let assistantContent = "";

    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) throw new Error("Not authenticated");

      const chatUrl = `${import.meta.env.VITE_SUPABASE_URL}/functions/v1/test-iching-agent`;

      const resp = await fetch(chatUrl, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${session.access_token}`,
          apikey: import.meta.env.VITE_SUPABASE_PUBLISHABLE_KEY,
        },
        body: JSON.stringify({
          messages: newMessages,
          scene_type: sceneType === "none" ? undefined : sceneType,
        }),
      });

      if (!resp.ok) {
        const errData = await resp.json().catch(() => ({ error: `HTTP ${resp.status}` }));
        throw new Error(errData.error || `HTTP ${resp.status}`);
      }

      if (!resp.body) throw new Error("No response body");

      const reader = resp.body.getReader();
      const decoder = new TextDecoder();
      let buffer = "";

      setMessages((prev) => [...prev, { role: "assistant", content: "" }]);

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        buffer += decoder.decode(value, { stream: true });

        let newlineIndex: number;
        while ((newlineIndex = buffer.indexOf("\n")) !== -1) {
          let line = buffer.slice(0, newlineIndex);
          buffer = buffer.slice(newlineIndex + 1);

          if (line.endsWith("\r")) line = line.slice(0, -1);
          if (line.startsWith(":") || line.trim() === "") continue;
          if (!line.startsWith("data: ")) continue;

          const jsonStr = line.slice(6).trim();
          if (jsonStr === "[DONE]") break;

          try {
            const parsed = JSON.parse(jsonStr);
            const content = parsed.choices?.[0]?.delta?.content;
            if (content) {
              assistantContent += content;
              const currentContent = assistantContent;
              setMessages((prev) => {
                const updated = [...prev];
                updated[updated.length - 1] = { role: "assistant", content: currentContent };
                return updated;
              });
            }
          } catch {
            buffer = line + "\n" + buffer;
            break;
          }
        }
      }

      // Final flush
      if (buffer.trim()) {
        for (let raw of buffer.split("\n")) {
          if (!raw) continue;
          if (raw.endsWith("\r")) raw = raw.slice(0, -1);
          if (raw.startsWith(":") || raw.trim() === "") continue;
          if (!raw.startsWith("data: ")) continue;
          const jsonStr = raw.slice(6).trim();
          if (jsonStr === "[DONE]") continue;
          try {
            const parsed = JSON.parse(jsonStr);
            const content = parsed.choices?.[0]?.delta?.content;
            if (content) {
              assistantContent += content;
            }
          } catch { /* ignore */ }
        }
      }

      // Save after complete response
      const finalMessages = [...newMessages, { role: "assistant" as const, content: assistantContent }];
      setMessages(finalMessages);
      debouncedSave(finalMessages, activeConversationId, sceneType);
    } catch (err: any) {
      console.error("Chat error:", err);
      const errorMsg = `Error: ${err.message}`;
      setMessages((prev) => {
        if (prev[prev.length - 1]?.role === "assistant" && prev[prev.length - 1]?.content === "") {
          const updated = [...prev];
          updated[updated.length - 1] = { role: "assistant", content: errorMsg };
          return updated;
        }
        return [...prev, { role: "assistant", content: errorMsg }];
      });
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const formatTime = (dateStr: string) => {
    const d = new Date(dateStr);
    const now = new Date();
    const diffMs = now.getTime() - d.getTime();
    const diffMin = Math.floor(diffMs / 60000);
    if (diffMin < 1) return t("admin.ichingAgent.justNow");
    if (diffMin < 60) return `${diffMin}m`;
    const diffH = Math.floor(diffMin / 60);
    if (diffH < 24) return `${diffH}h`;
    return d.toLocaleDateString();
  };

  return (
    <div className="flex border rounded-lg bg-card overflow-hidden" style={{ height: "calc(100vh - 200px)", minHeight: "400px" }}>
      {/* Sidebar - conversation list */}
      <div className="w-56 border-r bg-muted/20 flex flex-col shrink-0">
        <div className="p-2 border-b">
          <Button
            variant="outline"
            size="sm"
            className="w-full gap-1.5 text-xs h-8"
            onClick={startNew}
          >
            <Plus className="w-3.5 h-3.5" />
            {t("admin.ichingAgent.newConversation")}
          </Button>
        </div>
        <ScrollArea className="flex-1">
          <div className="p-1.5 space-y-0.5">
            {conversations.map((conv) => (
              <button
                key={conv.id}
                onClick={() => loadConversation(conv.id)}
                className={`group w-full text-left px-2.5 py-2 rounded-md text-xs transition-colors flex items-start gap-2 ${
                  activeConversationId === conv.id
                    ? "bg-primary/10 text-primary"
                    : "hover:bg-muted/60 text-foreground"
                }`}
              >
                <MessageSquare className="w-3.5 h-3.5 mt-0.5 shrink-0 opacity-50" />
                <div className="flex-1 min-w-0">
                  <p className="truncate font-medium leading-tight">{conv.title || t("admin.ichingAgent.untitledConversation")}</p>
                  <p className="text-[10px] text-muted-foreground mt-0.5 flex items-center gap-1">
                    <Clock className="w-2.5 h-2.5" />
                    {formatTime(conv.updated_at)}
                  </p>
                </div>
                <button
                  onClick={(e) => deleteConversation(conv.id, e)}
                  className="opacity-0 group-hover:opacity-100 p-0.5 hover:text-destructive transition-opacity shrink-0"
                >
                  <Trash2 className="w-3 h-3" />
                </button>
              </button>
            ))}
            {conversations.length === 0 && (
              <p className="text-[11px] text-muted-foreground text-center py-6">
                {t("admin.ichingAgent.noConversations")}
              </p>
            )}
          </div>
        </ScrollArea>
      </div>

      {/* Main chat area */}
      <div className="flex-1 flex flex-col min-w-0">
        {/* Toolbar */}
        <div className="flex items-center gap-2 px-3 py-2 border-b bg-muted/30">
          <LayoutTemplate className="w-3.5 h-3.5 text-muted-foreground shrink-0" />
          <Select value={sceneType} onValueChange={setSceneType}>
            <SelectTrigger className="h-7 text-xs w-40 border-none bg-transparent shadow-none focus:ring-0">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              {SCENE_OPTIONS.map((opt) => (
                <SelectItem key={opt.value} value={opt.value} className="text-xs">
                  {t(opt.labelKey)}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
          <div className="flex-1" />
          <span className="text-[10px] text-muted-foreground">
            {messages.filter((m) => m.role === "user").length} {t("admin.ichingAgent.messageCount")}
          </span>
          <Button
            variant="ghost"
            size="icon"
            className="h-7 w-7"
            onClick={startNew}
            disabled={messages.length === 0}
          >
            <Trash2 className="w-3.5 h-3.5" />
          </Button>
        </div>

        {/* Messages */}
        <div ref={scrollRef} className="flex-1 overflow-y-auto px-4 py-3 space-y-4">
          {messages.length === 0 && (
            <div className="flex flex-col items-center justify-center h-full gap-3 text-muted-foreground">
              <div className="w-12 h-12 rounded-full bg-primary/10 flex items-center justify-center">
                <Sparkles className="w-6 h-6 text-primary" />
              </div>
              <p className="text-sm">{t("admin.ichingAgent.testHint")}</p>
              <div className="flex flex-wrap gap-2 max-w-md justify-center">
                {[
                  t("admin.ichingAgent.quickPrompt1"),
                  t("admin.ichingAgent.quickPrompt2"),
                  t("admin.ichingAgent.quickPrompt3"),
                ].map((prompt, i) => (
                  <button
                    key={i}
                    className="text-xs px-3 py-1.5 rounded-full border hover:bg-accent/50 transition-colors text-foreground"
                    onClick={() => setInput(prompt)}
                  >
                    {prompt}
                  </button>
                ))}
              </div>
            </div>
          )}

          {messages.map((msg, i) => (
            <div key={i} className={`flex gap-2.5 ${msg.role === "user" ? "flex-row-reverse" : ""}`}>
              <div className={`w-7 h-7 rounded-full flex items-center justify-center shrink-0 mt-0.5 ${
                msg.role === "user" ? "bg-primary/10" : "bg-accent"
              }`}>
                {msg.role === "user" ? (
                  <User className="w-3.5 h-3.5 text-primary" />
                ) : (
                  <Sparkles className="w-3.5 h-3.5 text-primary" />
                )}
              </div>
              <div className={`max-w-[75%] rounded-xl px-3.5 py-2.5 text-sm ${
                msg.role === "user"
                  ? "bg-primary text-primary-foreground"
                  : "bg-muted/60 border"
              }`}>
                {msg.role === "assistant" ? (
                  <div className="prose prose-sm dark:prose-invert max-w-none [&_p]:my-1 [&_ul]:my-1 [&_ol]:my-1 [&_li]:my-0.5">
                    <ReactMarkdown>{msg.content || "..."}</ReactMarkdown>
                  </div>
                ) : (
                  <p className="whitespace-pre-wrap leading-relaxed">{msg.content}</p>
                )}
              </div>
            </div>
          ))}

          {isLoading && messages[messages.length - 1]?.role === "user" && (
            <div className="flex gap-2.5">
              <div className="w-7 h-7 rounded-full bg-accent flex items-center justify-center shrink-0">
                <Sparkles className="w-3.5 h-3.5 text-primary" />
              </div>
              <div className="bg-muted/60 border rounded-xl px-3.5 py-2.5">
                <div className="flex gap-1">
                  <span className="w-1.5 h-1.5 rounded-full bg-muted-foreground/40 animate-bounce" style={{ animationDelay: "0ms" }} />
                  <span className="w-1.5 h-1.5 rounded-full bg-muted-foreground/40 animate-bounce" style={{ animationDelay: "150ms" }} />
                  <span className="w-1.5 h-1.5 rounded-full bg-muted-foreground/40 animate-bounce" style={{ animationDelay: "300ms" }} />
                </div>
              </div>
            </div>
          )}
        </div>

        {/* Input area */}
        <div className="border-t bg-muted/20 p-3">
          <div className="flex gap-2.5 items-end max-w-3xl mx-auto">
            <div className="flex-1 relative">
              <Textarea
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={handleKeyDown}
                placeholder={t("admin.ichingAgent.testPlaceholder")}
                rows={1}
                className="resize-none text-[14px] leading-[1.6] min-h-[42px] max-h-[140px] py-2.5 px-3.5 rounded-xl bg-background border-border/60 focus:border-primary/40 transition-colors placeholder:text-muted-foreground/50 shadow-sm"
                disabled={isLoading}
                style={{ height: "auto" }}
                onInput={(e) => {
                  const target = e.target as HTMLTextAreaElement;
                  target.style.height = "auto";
                  target.style.height = Math.min(target.scrollHeight, 140) + "px";
                }}
              />
            </div>
            <Button
              size="icon"
              className="h-[42px] w-[42px] shrink-0 rounded-xl shadow-sm"
              onClick={handleSend}
              disabled={!input.trim() || isLoading}
            >
              {isLoading ? (
                <Loader2 className="w-4 h-4 animate-spin" />
              ) : (
                <Send className="w-4 h-4" />
              )}
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default IChingTestChatTab;
